import sys
from collections import deque

def main():
    n = int(sys.stdin.readline())
    a = list(map(int, sys.stdin.readline().split()))
    b = list(map(int, sys.stdin.readline().split()))

    dp = [float('inf')] * (n + 1)
    dp[n] = 0
    q = deque()
    q.append(n)

    while q:
        u = q.popleft()
        if u == 0:
            break
        for v in range(u - a[u - 1], u):
            if v >= 0:
                new_pos = v + b[v]
                if dp[new_pos] > dp[u] + 1:
                    dp[new_pos] = dp[u] + 1
                    q.append(new_pos)

    if dp[0] == float('inf'):
        print(-1)
        return

    print(dp[0])

    path = []
    current = 0
    while current != n:
        for v in range(n, -1, -1):
            if v + b[v] == current and dp[v] == dp[current] - 1:
                path.append(v)
                current = v
                break

    path.reverse()
    print(' '.join(map(str, path)))

if __name__ == "__main__":
    main()
